final:
module RefModule( D , Q , CLK
    );parameter DataSize = 1 ; 

	 input [ DataSize - 1 : 0 ] D ; 
	 input CLK ; 

	 output [ DataSize - 1 : 0 ] Q ; 
	 reg [ DataSize - 1 : 0 ] Q ;

	   wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @( posedge CLK  or posedge dbg_halt) 
		begin : FlipFlop
			Q <= D ;
		end

endmodule
